#[test]
fn chmod_recursive_applies_to_collection_children() {
    // Stage a parent collection containing one data object and one
    // sub-collection. chmod with --recurse on the parent — iRODS
    // walks server-side, so all three (parent, child object,
    // sub-coll) end up with public in their access list.
    let parent = "/testZone/home/irods/baton_rs_chmod_recurse";
    let sub_coll = format!("{}/sub", parent);
    let data_object = "child.txt";
    let data_path = format!("{}/{}", parent, data_object);

    imkdir(parent);
    imkdir(&sub_coll);
    let local = "/tmp/baton_rs_chmod_recurse_child";
    std::fs::write(local, b"recurse child").expect("write child");
    iput(local, &data_path);
    let _cleanup = IrodsCleanup(parent.to_string());

    let mut conn = RodsConnection::connect_from_env().expect("connect_from_env");
    conn.login_from_auth_file().expect("login_from_auth_file");

    let input = collection_target(
        parent,
        Some(vec![Acl {
            owner: PUBLIC_GROUP.to_string(),
            level: AclLevel::Read,
            zone: None,
        }]),
    );
    let opts = ChmodOptions { recursive: true };
    chmod_one(&mut conn, input, &opts).expect("chmod_one --recurse");

    // Parent collection.
    let parent_access = fetch_access(&mut conn, collection_target(parent, None));
    assert!(
        parent_access
            .iter()
            .any(|a| a.owner == PUBLIC_GROUP && a.level == AclLevel::Read),
        "parent should have public:read; got {:?}",
        parent_access
    );

    // Sub-collection.
    let sub_access = fetch_access(&mut conn, collection_target(&sub_coll, None));
    assert!(
        sub_access
            .iter()
            .any(|a| a.owner == PUBLIC_GROUP && a.level == AclLevel::Read),
        "sub-collection should have public:read after --recurse; got {:?}",
        sub_access
    );

    // Child data object.
    let obj_access = fetch_access(&mut conn, data_object_target(parent, data_object, None));
    assert!(
        obj_access
            .iter()
            .any(|a| a.owner == PUBLIC_GROUP && a.level == AclLevel::Read),
        "child data object should have public:read after --recurse; got {:?}",
        obj_access
    );
}

#[test]
fn chmod_empty_access_is_no_op() {
    // No access entries on the input → no rcModAccessControl calls,
    // no error, output echoes input. Pin that absence ≠ failure.
    let coll = "/testZone/home/irods/baton_rs_chmod_empty";
    imkdir(coll);
    let _cleanup = IrodsCleanup(coll.to_string());

    let mut conn = RodsConnection::connect_from_env().expect("connect_from_env");
    conn.login_from_auth_file().expect("login_from_auth_file");

    let pre = fetch_access(&mut conn, collection_target(coll, None));

    // Empty Vec — has the field, but no entries.
    let input = collection_target(coll, Some(Vec::new()));
    let output = chmod_one(&mut conn, input, &ChmodOptions::default())
        .expect("chmod_one empty access should succeed");

    let post = fetch_access(&mut conn, collection_target(coll, None));
    assert_eq!(
        pre, post,
        "empty access input should leave the catalog untouched"
    );

    // The output target echoes the input — empty access list
    // preserved (Some(vec![])), not collapsed to None.
    match output {
        Target::Collection(c) => assert_eq!(c.access, Some(Vec::new())),
        other => panic!("expected Collection, got {:?}", other),
    }

    // None access — same no-op behaviour, output preserves None.
    let input_none = collection_target(coll, None);
    let output_none = chmod_one(&mut conn, input_none, &ChmodOptions::default())
        .expect("chmod_one None access should succeed");
    match output_none {
        Target::Collection(c) => assert_eq!(c.access, None),
        other => panic!("expected Collection, got {:?}", other),
    }
}

#[test]
fn chmod_breaks_on_first_failure_in_array() {
    // Multi-entry access array where the *second* entry has a
    // bogus user. Per upstream baton (operations.c:420 — `goto
    // finally`), iteration stops at the failing entry: the first
    // entry is applied, the third is not. baton-rs mirrors this
    // for compat (#34 tracks the accumulate alternative).
    let coll = "/testZone/home/irods/baton_rs_chmod_break";
    imkdir(coll);
    let _cleanup = IrodsCleanup(coll.to_string());

    let bogus_user = format!("baton_rs_no_such_user_break_{}", std::process::id());
    assert!(
        !user_or_group_exists(&bogus_user),
        "test prerequisite: iRODS already has a user named {bogus_user:?}",
    );

    let mut conn = RodsConnection::connect_from_env().expect("connect_from_env");
    conn.login_from_auth_file().expect("login_from_auth_file");

    let input = collection_target(
        coll,
        Some(vec![
            Acl {
                // First entry: public read — should apply.
                owner: PUBLIC_GROUP.to_string(),
                level: AclLevel::Read,
                zone: None,
            },
            Acl {
                // Second entry: bogus user — should error here.
                owner: bogus_user.clone(),
                level: AclLevel::Read,
                zone: None,
            },
            Acl {
                // Third entry: public own — should NOT be applied,
                // because iteration breaks at the second.
                owner: PUBLIC_GROUP.to_string(),
                level: AclLevel::Own,
                zone: None,
            },
        ]),
    );
    let output = chmod_one_annotated(&mut conn, input, &ChmodOptions::default());
    let err = match &output {
        Target::Collection(c) => &c.error,
        other => panic!("expected Collection, got {:?}", other),
    };
    assert!(
        err.is_some(),
        "expected error annotation for bogus user in middle position"
    );

    // Check post-state: public should have read (first entry
    // applied), NOT own (third entry skipped due to break-on-first-
    // failure). This is the load-bearing assertion that pins the
    // upstream-parity break behaviour.
    let access = fetch_access(&mut conn, collection_target(coll, None));
    let public_entry = access.iter().find(|a| a.owner == PUBLIC_GROUP);
    assert!(
        matches!(public_entry, Some(a) if a.level == AclLevel::Read),
        "first entry (public:read) should have been applied before the failure; \
         third entry (public:own) should NOT have been applied. Got {:?}",
        access
    );
}

#[test]
fn chmod_recovers_from_error_on_same_connection() {
    // Failing record (bogus user → annotated error) followed by a
    // valid record on the same RodsConnection both processed.
    // Pins that the close-on-error path inside chmod_one /
    // mod_access_control leaves the connection clean for the next
    // iteration — the contract baton-chmod's NDJSON loop relies
    // on. Mirrors the equivalent put / get tests.
    let coll = "/testZone/home/irods/baton_rs_chmod_recover";
    imkdir(coll);
    let _cleanup = IrodsCleanup(coll.to_string());

    let bogus_user = format!("baton_rs_no_such_user_recover_{}", std::process::id());
    assert!(!user_or_group_exists(&bogus_user));

    let mut conn = RodsConnection::connect_from_env().expect("connect_from_env");
    conn.login_from_auth_file().expect("login_from_auth_file");

    // Bad input first.
    let bad_input = collection_target(
        coll,
        Some(vec![Acl {
            owner: bogus_user,
            level: AclLevel::Read,
            zone: None,
        }]),
    );
    let bad_out = chmod_one_annotated(&mut conn, bad_input, &ChmodOptions::default());
    let bad_err = match bad_out {
        Target::Collection(c) => c.error,
        other => panic!("expected Collection, got {:?}", other),
    };
    assert!(bad_err.is_some(), "expected error annotation on bogus user");

    // Valid input on the same connection.
    let good_input = collection_target(
        coll,
        Some(vec![Acl {
            owner: PUBLIC_GROUP.to_string(),
            level: AclLevel::Read,
            zone: None,
        }]),
    );
    chmod_one(&mut conn, good_input, &ChmodOptions::default())
        .expect("chmod_one after annotated error on same connection");

    let access = fetch_access(&mut conn, collection_target(coll, None));
    assert!(
        access
            .iter()
            .any(|a| a.owner == PUBLIC_GROUP && a.level == AclLevel::Read),
        "post-recovery grant should have applied; got {:?}",
        access
    );
}
